echo "Ō£ģ Environment file created at /app/.env"

# Ensure uploads directory exists with correct permissions
echo "­¤ōü Setting up uploads directory..."
mkdir -p /uploads
chmod 755 /uploads
echo "Ō£ģ Uploads directory ready"

# Run database migrations
echo "­¤Śä’ĖÅ  Running database migrations..."
pnpm run prisma-db-push || echo "ŌÜĀ’ĖÅ  Database migration failed or already up to date"

# Start nginx
echo "­¤īÉ Starting nginx..."
nginx

# Start applications with PM2
echo "­¤ÜĆ Starting applications..."
cd /app
exec pnpm run pm2
